import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class InputHandlerServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("userInput");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>XSS Secure Example</title></head>");
        out.println("<body>");
        out.println("<h1>User Input:</h1>");

        // Sanitize and encode user input to prevent XSS attacks
        Encoder encoder = ESAPI.encoder();
        String safeUserInput = encoder.encodeForHTML(userInput);

        out.println(safeUserInput);
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
